vector<int> removeDuplicates(const vector<int>& arr) {
    vector<int> result;
    for (int i = 0; i < arr.size(); i++) {
        bool isDuplicate = false;
        for (int j = 0; j < result.size(); j++) {
            if (arr[i] == result[j]) {
                isDuplicate = true;
                break;
            }
        }
        if (!isDuplicate) {
            result.push_back(arr[i]);
        }
    }
    return result;
}

