solutions.c:
int* removeDuplicates(int arr[], int size, int* newSize) {
    int* result = malloc(size * sizeof(int));
    *newSize = 0;

    for (int i = 0; i < size; i++) {
        int isDuplicate = 0;
        for (int j = 0; j < *newSize; j++) {
            if (arr[i] == result[j]) {
                isDuplicate = 1;
                break;
            }
        }
        if (!isDuplicate) {
            result[(*newSize)++] = arr[i];
        }
    }

    return result;
}
